const crypto = require('crypto');
const fs = require('fs');
const https = require('https');

const sa = JSON.parse(fs.readFileSync('/home/node/service-account.json', 'utf8'));

const header = Buffer.from(JSON.stringify({alg: 'RS256', typ: 'JWT'})).toString('base64url');
const now = Math.floor(Date.now() / 1000);
const payload = Buffer.from(JSON.stringify({
  iss: sa.client_email,
  scope: 'https://www.googleapis.com/auth/calendar',
  aud: 'https://oauth2.googleapis.com/token',
  iat: now,
  exp: now + 3600
})).toString('base64url');

const signingInput = header + '.' + payload;
const sign = crypto.createSign('RSA-SHA256');
sign.update(signingInput);
const signature = sign.sign(sa.private_key, 'base64url');
const jwt = signingInput + '.' + signature;

const postData = 'grant_type=urn%3Aietf%3Aparams%3Aoauth%3Agrant-type%3Ajwt-bearer&assertion=' + jwt;

const tokenData = await new Promise((resolve, reject) => {
  const req = https.request('https://oauth2.googleapis.com/token', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
      'Content-Length': Buffer.byteLength(postData)
    }
  }, (res) => {
    let data = '';
    res.on('data', (chunk) => data += chunk);
    res.on('end', () => resolve(JSON.parse(data)));
  });
  req.on('error', reject);
  req.write(postData);
  req.end();
});

const items = $input.all();
return items.map(item => ({
  json: {
    ...item.json,
    googleToken: tokenData.access_token,
    calendarId: 'ae4d71467b7b1970bac78ebbfc075f2c3451427a3bf7cdddce921bbce0b92344@group.calendar.google.com'
  }
}));

