const crypto = require('crypto');
const fs = require('fs');
const https = require('https');

let input;
try {
  input = typeof query === 'string' ? JSON.parse(query) : query;
} catch (e) {
  return `Error: Invalid input. Got: ${query}`;
}

const { date, time, duration_minutes } = input;
if (!date || !time || !duration_minutes) return 'Error: Missing date, time, or duration_minutes.';
if (!/^\d{4}-\d{2}-\d{2}$/.test(date)) return `Error: Invalid date '${date}'. Use YYYY-MM-DD.`;
if (!/^\d{2}:\d{2}$/.test(time)) return `Error: Invalid time '${time}'. Use HH:MM.`;

const checkDate = new Date(date + 'T12:00:00');
const dayOfWeek = checkDate.getDay();
if (dayOfWeek === 0) return 'NOT AVAILABLE: Closed on Sundays.';

const [hours, minutes] = time.split(':').map(Number);
const startMin = hours * 60 + minutes;
const endMin = startMin + Number(duration_minutes);
if (startMin < 540 || endMin > 1200) return `NOT AVAILABLE: ${time} with ${duration_minutes}min is outside 09:00-20:00.`;

const endH = Math.floor(endMin / 60).toString().padStart(2, '0');
const endM = (endMin % 60).toString().padStart(2, '0');
const endTime = `${endH}:${endM}`;

function getToken() {
  const sa = JSON.parse(fs.readFileSync('/home/node/service-account.json', 'utf8'));
  const hdr = Buffer.from(JSON.stringify({alg:'RS256',typ:'JWT'})).toString('base64url');
  const now = Math.floor(Date.now()/1000);
  const pl = Buffer.from(JSON.stringify({iss:sa.client_email,scope:'https://www.googleapis.com/auth/calendar',aud:'https://oauth2.googleapis.com/token',iat:now,exp:now+3600})).toString('base64url');
  const si = hdr+'.'+pl;
  const sign = crypto.createSign('RSA-SHA256');
  sign.update(si);
  const sig = sign.sign(sa.private_key,'base64url');
  const jwt = si+'.'+sig;
  const pd = 'grant_type=urn%3Aietf%3Aparams%3Aoauth%3Agrant-type%3Ajwt-bearer&assertion='+jwt;
  return new Promise((resolve,reject) => {
    const req = https.request('https://oauth2.googleapis.com/token',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded','Content-Length':Buffer.byteLength(pd)}},(res)=>{let d='';res.on('data',c=>d+=c);res.on('end',()=>resolve(JSON.parse(d)));});
    req.on('error',reject);req.write(pd);req.end();
  });
}

function gcalGet(token, calId, params) {
  const qs = Object.entries(params).map(([k,v])=>k+'='+encodeURIComponent(v)).join('&');
  const url = `/calendar/v3/calendars/${encodeURIComponent(calId)}/events?${qs}`;
  return new Promise((resolve,reject) => {
    const req = https.request({hostname:'www.googleapis.com',path:url,method:'GET',headers:{'Authorization':'Bearer '+token}},(res)=>{let d='';res.on('data',c=>d+=c);res.on('end',()=>resolve(JSON.parse(d)));});
    req.on('error',reject);req.end();
  });
}

const calId = 'ae4d71467b7b1970bac78ebbfc075f2c3451427a3bf7cdddce921bbce0b92344@group.calendar.google.com';

try {
  const tokenData = await getToken();
  const token = tokenData.access_token;
  if (!token) return `Error getting Google token: ${JSON.stringify(tokenData)}`;
  const resp = await gcalGet(token, calId, {
    timeMin: `${date}T${time}:00-03:00`,
    timeMax: `${date}T${endTime}:00-03:00`,
    singleEvents: 'true',
    orderBy: 'startTime'
  });
  const busy = (resp.items||[]).filter(e=>e.status!=='cancelled');
  if (busy.length === 0) {
    const sat = dayOfWeek===6?' (Saturday - special appointment, requires confirmation)':'';
    return `AVAILABLE${sat}: ${date} ${time}-${endTime} (${duration_minutes} min) is free.`;
  } else {
    const list = busy.map(e=>{const s=e.start.dateTime?e.start.dateTime.substring(11,16):e.start.date;const en=e.end.dateTime?e.end.dateTime.substring(11,16):e.end.date;return `${s}-${en}: ${e.summary||'Appointment'}`;}).join('; ');
    return `NOT AVAILABLE: ${date} ${time} conflicts with: ${list}.`;
  }
} catch(err) {
  return `AVAILABLE (unverified - API error: ${err.message}): Hours OK for ${date} ${time}-${endTime}. Verify manually.`;
}

